    User = apps.get_model("library", "Utilisateur")

    def create_user(email, password, role, prenom, nom, is_superuser=False):
        if not email or not password:
            return
        if User.objects.filter(email__iexact=email).exists():
            return
        normalized_email = email.strip().lower()
        user = User(
            email=normalized_email,
            prenom=prenom,
            nom=nom,
            role=role,
            is_active=True,
            is_staff=role in ("ADMIN", "BIBLIOTHECAIRE"),
            is_superuser=is_superuser,
            password=make_password(password),
        )
        user.save()
        prefix = "ADM" if role == "ADMIN" else "BIB" if role == "BIBLIOTHECAIRE" else "ADH"
        user.matricule = f"{prefix}-{user.id:05d}"
        user.save(update_fields=["matricule"])

